 1→export interface Customer {
 2→  /** Existing tier field — no longer used in discount calculation */
 3→  tier?: "premium" | "gold" | "standard";
 4→  /** Date the customer account was created */
 5→  accountCreatedAt: Date;
 6→  /** Full list of purchase dates for this customer */
 7→  purchases: Date[];
 8→}
 9→
10→const NEW_CUSTOMER_THRESHOLD_DAYS = 30;
11→const WIN_BACK_WINDOW_DAYS = 90;
12→
13→const NEW_CUSTOMER_DISCOUNT = 0.05;   // 5%
14→const WIN_BACK_DISCOUNT = 0.03;       // 3%
15→const ACTIVE_CUSTOMER_DISCOUNT = 0;   // 0%
16→
17→function daysBetween(earlier: Date, later: Date): number {
18→  const msPerDay = 1000 * 60 * 60 * 24;
19→  return (later.getTime() - earlier.getTime()) / msPerDay;
20→}
21→
22→/**
23→ * Calculate the discount rate for a customer based on account age
24→ * and recent purchase activity.
25→ *
26→ * @param customer - The customer to evaluate
27→ * @param now      - Reference date (defaults to current time; injectable for testing)
28→ * @returns Discount rate as a decimal (e.g. 0.05 = 5%)
29→ */
30→export function calculateDiscount(customer: Customer, now: Date = new Date()): number {
31→  const accountAgeDays = daysBetween(customer.accountCreatedAt, now);
32→
33→  // AC1: New customer — account less than 30 days old
34→  if (accountAgeDays < NEW_CUSTOMER_THRESHOLD_DAYS) {
35→    return NEW_CUSTOMER_DISCOUNT;
36→  }
37→
38→  // AC2 / AC3: Returning customer — check for purchases in the last 90 days
39→  const windowStart = new Date(now.getTime() - WIN_BACK_WINDOW_DAYS * 24 * 60 * 60 * 1000);
40→  const hasRecentPurchase = customer.purchases.some(
41→    (purchaseDate) => purchaseDate >= windowStart && purchaseDate <= now
42→  );
43→
44→  // AC3: Active returning customer — at least one purchase in the last 90 days
45→  if (hasRecentPurchase) {
46→    return ACTIVE_CUSTOMER_DISCOUNT;
47→  }
48→
49→  // AC2: Lapsed returning customer — no purchases in the last 90 days (win-back rate)
50→  return WIN_BACK_DISCOUNT;
51→}
