 1→// ─── Types ────────────────────────────────────────────────────────────────────
 2→
 3→export interface Seat {
 4→  id: string;
 5→  status: "available" | "reserved";
 6→  userId?: string;
 7→}
 8→
 9→export interface Reservation {
10→  seatId: string;
11→  userId: string;
12→  reservedAt: Date;
13→}
14→
15→export interface Database {
16→  findSeat(seatId: string): Promise<Seat | null>;
17→  /**
18→   * Atomically update the seat status.
19→   * Returns true  if the row was updated  (current status matched expectedCurrentStatus).
20→   * Returns false if the row was NOT updated (optimistic-lock conflict — another writer won).
21→   */
22→  updateSeatStatus(
23→    seatId: string,
24→    status: string,
25→    userId: string,
26→    expectedCurrentStatus: string
27→  ): Promise<boolean>;
28→}
29→
30→// ─── Error codes ──────────────────────────────────────────────────────────────
31→
32→export type ReservationErrorCode = "SEAT_NOT_FOUND" | "SEAT_ALREADY_RESERVED";
33→
34→export class ReservationError extends Error {
35→  readonly code: ReservationErrorCode;
36→
37→  constructor(code: ReservationErrorCode, message: string) {
38→    super(message);
39→    this.name = "ReservationError";
40→    this.code = code;
41→  }
42→}
43→
44→// ─── Implementation ───────────────────────────────────────────────────────────
45→
46→export async function reserveSeat(
47→  seatId: string,
48→  userId: string,
49→  db: Database
50→): Promise<Reservation> {
51→  // AC4: seat must exist
52→  const seat = await db.findSeat(seatId);
53→  if (seat === null) {
54→    throw new ReservationError("SEAT_NOT_FOUND", `Seat ${seatId} does not exist`);
55→  }
56→
57→  // AC2: fast-path check — seat already reserved at read time
58→  if (seat.status !== "available") {
59→    throw new ReservationError(
60→      "SEAT_ALREADY_RESERVED",
61→      `Seat ${seatId} is already reserved`
62→    );
63→  }
64→
65→  // AC1 + AC3: attempt atomic update — only succeeds if status is still 'available'
66→  // This is the optimistic-lock guard that prevents double-reservations under concurrency.
67→  const updated = await db.updateSeatStatus(seatId, "reserved", userId, "available");
68→
69→  if (!updated) {
70→    // Another concurrent call won the race between our findSeat read and this update.
71→    throw new ReservationError(
72→      "SEAT_ALREADY_RESERVED",
73→      `Seat ${seatId} was reserved by another request`
74→    );
75→  }
76→
77→  return {
78→    seatId,
79→    userId,
80→    reservedAt: new Date(),
81→  };
82→}
