 1→/**
 2→ * Shipping Calculator
 3→ *
 4→ * Supported destinations and their per-kg rates:
 5→ *   - "domestic"         → weight * 2.5  (standard ground)
 6→ *   - "international"    → weight * 7.5  (cross-border)
 7→ *   - "express_domestic" → weight * 4.0  (expedited domestic)
 8→ *   - "freight"          → weight * 1.5  (bulk / cheaper per-kg)
 9→ *
10→ * Validation:
11→ *   - Weight must be > 0; otherwise throws with code INVALID_WEIGHT.
12→ *   - Unknown destination strings throw with code UNKNOWN_DESTINATION.
13→ *
14→ * Signature is intentionally unchanged per MJ's constraint.
15→ */
16→
17→export class ShippingError extends Error {
18→  constructor(
19→    message: string,
20→    public readonly code: "INVALID_WEIGHT" | "UNKNOWN_DESTINATION"
21→  ) {
22→    super(message);
23→    this.name = "ShippingError";
24→  }
25→}
26→
27→const RATES: Record<string, number> = {
28→  domestic: 2.5,
29→  international: 7.5,
30→  express_domestic: 4.0,
31→  freight: 1.5,
32→};
33→
34→export function calculateShipping(weight: number, destination: string): number {
35→  if (weight <= 0) {
36→    throw new ShippingError(
37→      `Invalid weight: ${weight}. Weight must be greater than 0.`,
38→      "INVALID_WEIGHT"
39→    );
40→  }
41→
42→  const rate = RATES[destination];
43→
44→  if (rate === undefined) {
45→    throw new ShippingError(
46→      `Unknown destination: "${destination}". Valid destinations are: ${Object.keys(RATES).join(", ")}.`,
47→      "UNKNOWN_DESTINATION"
48→    );
49→  }
50→
51→  return weight * rate;
52→}
53→

 1→/**
 2→ * Tax brackets:
 3→ *   income <= 0          : throws INVALID_INCOME
 4→ *   0 < income < 10_000  : 0%  (tax = 0)
 5→ *   10_000 <= income <= 50_000  : 10% flat
 6→ *   50_001 <= income <= 150_000 : 25% flat
 7→ *   income > 150_000            : 40% flat
 8→ */
 9→
10→export class TaxError extends Error {
11→  constructor(
12→    public readonly code: string,
13→    message: string
14→  ) {
15→    super(message);
16→    this.name = "TaxError";
17→  }
18→}
19→
20→export function calculateTax(income: number): number {
21→  if (income <= 0) {
22→    throw new TaxError(
23→      "INVALID_INCOME",
24→      `Income must be a positive number, received: ${income}`
25→    );
26→  }
27→
28→  if (income < 10_000) {
29→    return 0;
30→  }
31→
32→  if (income <= 50_000) {
33→    return income * 0.10;
34→  }
35→
36→  if (income <= 150_000) {
37→    return income * 0.25;
38→  }
39→
40→  return income * 0.40;
41→}
